def strip_items(iterable):
    for item in iterable:
        yield item.strip()

def filter_empty(iterable):
    for item in iterable:
        if item:
            yield item

def to_upper(iterable):
    for item in iterable:
        yield item.upper()

def pipeline(data):
    return to_upper(filter_empty(strip_items(data)))

import time

class Timer:
    def __init__(self):
        self.elapsed = 0.0
        self._start = 0.0

    def __enter__(self):
        self._start = time.perf_counter()
        return self

    def __exit__(self, exc_type, exc_val, exc_tb):
        self.elapsed = time.perf_counter() - self._start
        print(f'Timer: {self.elapsed:.2f}s')
        if exc_type:
            print(f'Exception: {exc_type.__name__}: {exc_val}')
        return False  # Don't suppress exceptions

from itertools import groupby
from operator import itemgetter

def group_by_dept(employees):
    return {
        dept: [name for _, name in group]
        for dept, group in groupby(employees, key=itemgetter(0))
    }

from functools import reduce

def nested_dict(keys, value):
    return reduce(lambda acc, key: {key: acc}, reversed(keys), value)

class Temperature:
    def __init__(self, celsius=0):
        self.celsius = celsius  # Uses the setter

    @property
    def celsius(self):
        return self._celsius

    @celsius.setter
    def celsius(self, value):
        if value < -273.15:
            raise ValueError('Temperature below absolute zero')
        self._celsius = value

    @property
    def fahrenheit(self):
        return self._celsius * 9/5 + 32

class Fibonacci:
    def __init__(self, max_val):
        self.max_val = max_val
        self.a, self.b = 0, 1

    def __iter__(self):
        self.a, self.b = 0, 1
        return self

    def __next__(self):
        if self.a > self.max_val:
            raise StopIteration
        result = self.a
        self.a, self.b = self.b, self.a + self.b
        return result

class TypedField:
    def __init__(self, expected_type):
        self.expected_type = expected_type
        self.name = None

    def __set_name__(self, owner, name):
        self.name = name

    def __get__(self, obj, objtype=None):
        if obj is None:
            return self
        return obj.__dict__.get(self.name)

    def __set__(self, obj, value):
        if not isinstance(value, self.expected_type):
            raise TypeError(
                f'{self.name} must be {self.expected_type.__name__}, '
                f'got {type(value).__name__}'
            )
        obj.__dict__[self.name] = value

from concurrent.futures import ThreadPoolExecutor, as_completed

def fetch_lengths(urls, max_workers=4):
    def fetch(url):
        try:
            return url, len(url)  # simulated
        except Exception:
            return url, -1

    results = {}
    with ThreadPoolExecutor(max_workers=max_workers) as executor:
        futures = {executor.submit(fetch, url): url for url in urls}
        for future in as_completed(futures):
            url, length = future.result()
            results[url] = length
    return results

from collections import defaultdict

class EventEmitter:
    def __init__(self):
        self._listeners = defaultdict(list)

    def on(self, event, callback):
        self._listeners[event].append(callback)

    def off(self, event, callback):
        try:
            self._listeners[event].remove(callback)
        except ValueError:
            pass

    def emit(self, event, *args, **kwargs):
        for callback in self._listeners.get(event, []):
            callback(*args, **kwargs)

import functools

def count_calls(func):
    @functools.wraps(func)
    def wrapper(*args, **kwargs):
        wrapper.call_count += 1
        return func(*args, **kwargs)
    wrapper.call_count = 0
    return wrapper
